// ─── Parse Classifier JSON Output Safely ───
const rawText = $json.output || $json.text || $json.response || '';
const extractedData = $('clasifyer').first().json;

let parsed;
try {
  let cleaned = rawText
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();

  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  if (jsonMatch) cleaned = jsonMatch[0];

  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {
    classification: 'related',
    related_parts: [extractedData.messageText],
    unrelated_parts: [],
    query_type: 'general',
    is_time_sensitive: false,
    messageText: extractedData.messageText
  };
}

const validClassifications = ['related', 'unrelated', 'mixed'];
const validLanguages = ['hindi', 'english', 'hinglish'];

return [{
  json: {
    classification:    validClassifications.includes(parsed.classification) ? parsed.classification : 'related',
    related_parts:     Array.isArray(parsed.related_parts)   ? parsed.related_parts   : [extractedData.messageText],
    unrelated_parts:   Array.isArray(parsed.unrelated_parts) ? parsed.unrelated_parts : [],
    detected_language: validLanguages.includes(parsed.detected_language)   ? parsed.detected_language : 'hinglish',
    is_time_sensitive: !!parsed.is_time_sensitive,
    query_type:        parsed.query_type || 'general',
    chatId:            extractedData.chatId,
    senderName:        extractedData.senderName,
    messageText:       extractedData.messageText
  }
}];

// ─── Clean Agent Output ───
const agentOutput = $json.output || '';
const chatId = $('Code in JavaScript').first().json.chatId;
const detectedLanguage = $('Code in JavaScript').first().json.detected_language || 'hinglish';

let clean = agentOutput
  .replace(/\*\*(.*?)\*\*/g, '$1')
  .replace(/\*(.*?)\*/g, '$1')
  .replace(/^\s*[-*+]\s+/gm, '· ')
  .replace(/^\s*\d+\.\s+/gm, '· ')
  .replace(/#{1,6}\s+/g, '')
  .replace(/`{1,3}[^`]*`{1,3}/g, '')
  .trim();

clean = clean
  .split('\n')
  .map(line => line.trimEnd())
  .join('\n');

return [{ json: { output: clean, chatId, detectedLanguage } }];
